func TestDefaultAssetLayout(t *testing.T) {
	root, err := defaultAssetRoot()
	if err != nil {
		t.Fatal(err)
	}
	for _, path := range []string{
		filepath.Join(root, "check.yaml"),
		filepath.Join(root, "rules", "technical.yaml"),
		filepath.Join(root, "rules", "planning.yaml"),
		filepath.Join(root, "rules", "public.yaml"),
		filepath.Join(root, "vocabulary", "default.yaml"),
	} {
		if _, err := os.Stat(path); err != nil {
			t.Fatalf("expected asset %s: %v", path, err)
		}
	}

	cfg, err := loadDefaultConfig()
	if err != nil {
		t.Fatal(err)
	}
	if cfg.Mode != string(ModeTechnical) || cfg.Policy != "advisory" || cfg.Runner != "embedded" {
		t.Fatalf("unexpected default config: %+v", cfg)
	}

	vocab, err := loadDefaultVocabulary()
	if err != nil {
		t.Fatal(err)
	}
	if !containsAll(vocab.Accept, []string{"DDx", "bead", "execution"}) {
		t.Fatalf("default accept vocabulary missing DDx terms: %+v", vocab.Accept)
	}
	if !containsAll(vocab.Reject, []string{"system", "solution"}) {
		t.Fatalf("default reject vocabulary missing generic terms: %+v", vocab.Reject)
	}
}

func TestProseCheckerChangedMode(t *testing.T) {
	cases := listFixtureCases(t, "testdata/fixtures")
	for _, tc := range cases {
		t.Run(tc.Mode+"/"+tc.Name, func(t *testing.T) {
			checker, err := NewChecker(Mode(tc.Mode), Vocabulary{})
			if err != nil {
				t.Fatal(err)
			}
			got := checker.Findings("input.md", tc.Input)
			if !sameFindings(got, tc.Findings) {
				t.Fatalf("fixture mismatch for %s/%s\n--- got ---\n%v\n--- want ---\n%v", tc.Mode, tc.Name, got, tc.Findings)
			}
		})
	}
}

func TestProseCheckerPathMode(t *testing.T) {
	checker, err := NewChecker(ModeTechnical, Vocabulary{})
	if err != nil {
		t.Fatal(err)
	}
	input := strings.Join([]string{
		"## Technical Context",
		"",
		"This is robust and comprehensive.",
	}, "\n")
	findings := checker.Findings("docs/helix/example.md", input)
	if len(findings) != 1 {
		t.Fatalf("expected one finding, got %+v", findings)
	}
	if findings[0].File != "docs/helix/example.md" {
		t.Fatalf("unexpected file in finding: %+v", findings[0])
	}
}

func sameFindings(got, want []Finding) bool {
	if len(got) != len(want) {
		return false
	}
	for i := range got {
		if got[i] != want[i] {
			return false
		}
	}
	return true
}

func containsAll(got []string, want []string) bool {
	m := make(map[string]bool, len(got))
	for _, s := range got {
		m[s] = true
	}
	for _, s := range want {
		if !m[s] {
			return false
		}
	}
	return true
}

package docprose

import (
	"fmt"
	"os"
	"path/filepath"
	"runtime"

	"gopkg.in/yaml.v3"
)

const assetRootDir = "library/checks/prose-quality"

type defaultConfig struct {
	Mode       string     `yaml:"mode"`
	Severity   string     `yaml:"severity"`
	Policy     string     `yaml:"policy"`
	Runner     string     `yaml:"runner"`
	Includes   []string   `yaml:"includes"`
	Excludes   []string   `yaml:"excludes"`
	Vocabulary Vocabulary `yaml:"vocabulary"`
}

type rulePack struct {
	Mode  string     `yaml:"mode"`
	Rules []ruleSpec `yaml:"rules"`
}

type ruleSpec struct {
	ID            string   `yaml:"id"`
	Severity      string   `yaml:"severity"`
	Rationale     string   `yaml:"rationale"`
	SuggestedEdit string   `yaml:"suggested_edit"`
	ContainsAny   []string `yaml:"contains_any,omitempty"`
	Kind          string   `yaml:"kind,omitempty"`
}

type Vocabulary struct {
	Accept []string `yaml:"accept"`
	Reject []string `yaml:"reject"`
}

func defaultAssetRoot() (string, error) {
	_, file, _, ok := runtime.Caller(0)
	if !ok {
		return "", fmt.Errorf("locate docprose assets: runtime caller unavailable")
	}
	dir := filepath.Dir(file)
	root := filepath.Clean(filepath.Join(dir, "..", "..", ".."))
	return filepath.Join(root, assetRootDir), nil
}

func loadDefaultConfig() (defaultConfig, error) {
	root, err := defaultAssetRoot()
	if err != nil {
		return defaultConfig{}, err
	}
	data, err := os.ReadFile(filepath.Join(root, "check.yaml"))
	if err != nil {
		return defaultConfig{}, fmt.Errorf("read default config: %w", err)
	}
	var cfg defaultConfig
	if err := yaml.Unmarshal(data, &cfg); err != nil {
		return defaultConfig{}, fmt.Errorf("parse default config: %w", err)
	}
	return cfg, nil
}

func loadRulePack(mode string) ([]ruleSpec, error) {
	root, err := defaultAssetRoot()
	if err != nil {
		return nil, err
	}
	data, err := os.ReadFile(filepath.Join(root, "rules", mode+".yaml"))
	if err != nil {
		return nil, fmt.Errorf("read %s rules: %w", mode, err)
	}
	var pack rulePack
	if err := yaml.Unmarshal(data, &pack); err != nil {
		return nil, fmt.Errorf("parse %s rules: %w", mode, err)
	}
	if pack.Mode != mode {
		return nil, fmt.Errorf("rules file mode %q does not match requested mode %q", pack.Mode, mode)
	}
	return pack.Rules, nil
}

func loadDefaultVocabulary() (Vocabulary, error) {
	root, err := defaultAssetRoot()
	if err != nil {
		return Vocabulary{}, err
	}
	data, err := os.ReadFile(filepath.Join(root, "vocabulary", "default.yaml"))
	if err != nil {
		return Vocabulary{}, fmt.Errorf("read default vocabulary: %w", err)
	}
	var vocab Vocabulary
	if err := yaml.Unmarshal(data, &vocab); err != nil {
		return Vocabulary{}, fmt.Errorf("parse default vocabulary: %w", err)
	}
	return vocab, nil
}

