    58		data, err := os.ReadFile(filepath.Join(root, "check.yaml"))
    59		if err != nil {
    60			return defaultConfig{}, fmt.Errorf("read default config: %w", err)
    61		}
    62		var cfg defaultConfig
    63		if err := yaml.Unmarshal(data, &cfg); err != nil {
    64			return defaultConfig{}, fmt.Errorf("parse default config: %w", err)
    65		}
    66		return cfg, nil
    67	}
